}

html { scroll-behavior: smooth; }

body {
  font-family: var(--font-body);
  background: var(--color-cream);
  color: var(--color-ink);
  -webkit-font-smoothing: antialiased;
  margin: 0;
}

::selection { background: rgba(26, 177, 210, 0.15); }

